// 0 = más cotizados (desc), 1 = menos cotizados (asc), 2 = orden original
let sortRankingMode = 0;

function equipKey(idx, btu) {
  return `${idx}__${btu}`;
}

function getSelectedEquipmentItems() {
  return Object.entries(selectedEquipments)
    .map(([key, qty]) => {
      const [idxStr, btuStr] = key.split('__');
      const idx = Number(idxStr);
      const btu = Number(btuStr);
      const ac = allAC[idx];
      if (!ac || !qty) return null;
      const cap = (ac.capacities || []).find(c => Number(c.btu_capacity) === btu);
      if (!cap) return null;
      return { key, idx, btu, qty, ac, cap };
    })
    .filter(Boolean);
}

function getEquipmentTotalPrice() {
  return getSelectedEquipmentItems().reduce((sum, item) => sum + (item.cap.price_with_tax * item.qty), 0);
}

function updateStep1NextButton() {
  const btn = document.getElementById('btnStep1Next');
  if (!btn) return;
  const hasItems = getSelectedEquipmentItems().length > 0;
  btn.disabled = !hasItems;
  btn.style.opacity = hasItems ? '1' : '0.4';
}

function getEquipCount() {
  return getSelectedEquipmentItems().reduce((sum, item) => sum + item.qty, 0);
}

function preloadInstallationsFromEquipment() {
  const equipCount = getEquipCount();
  if (equipCount === 0) {
    serviceQtyMap.instalacion = 0;
  } else if ((serviceQtyMap.instalacion || 0) === 0) {
    // Precarga por defecto: 1 instalacion por cada equipo agregado.
    serviceQtyMap.instalacion = equipCount;
  } else {
    // Clamp por si el usuario quitó equipos después de haber puesto instalaciones
    serviceQtyMap.instalacion = Math.min(serviceQtyMap.instalacion, equipCount);
  }
  updateMultiServiceInputs();
  updateStep2NextButton();
  renderServiceGrid();
}

// ============================================================
// INIT
// ============================================================
async function init() {
  try { await generateQuoteNumber(); } catch(e) {}
  try { renderAccGrid(); } catch(e) {}
  try { renderServiceGrid(); } catch(e) {}
  try { updateMultiServiceInputs(); } catch(e) {}
  try { updateStep2NextButton(); } catch(e) {}

  // Priorizar Firebase fijo en codigo. Si no hay config o falla, usar demo.
  const activeUrl = FIREBASE_CONNECTION.databaseURL;
  const activeNode = FIREBASE_CONNECTION.node || 'air_conditioners';
  const activeToken = FIREBASE_CONNECTION.authToken || '';

  if (activeUrl) {
    // Carga equipos y accesorios en paralelo desde Firebase
    await Promise.all([
      loadFromFirebase(activeUrl, activeNode, activeToken),
      loadAccessoriesFromFirebase(activeUrl, activeToken)
    ]);
  } else {
    loadDemoData();
    showFirebaseStatus('error', 'Sin Firebase configurado — usando datos demo');
  }

  window.__cotizAppReady = true;
  document.dispatchEvent(new CustomEvent('cotiz:app-ready'));
  updateSortBtn(); // refleja modo inicial en el botón
  loadRankings().then(() => { if (Object.keys(acRankings).length > 0) filterAC(); }); // activa sort al cargar
}

async function loadRankings() {
  if (!window.RankingRepo || !window.FirebaseAuthService) return;
  const user = window.FirebaseAuthService.getCurrentUser();
  if (!user) return;
  try {
    const idToken = await window.FirebaseAuthService.getValidIdToken();
    acRankings = await window.RankingRepo.getRankings(user.uid, idToken);
  } catch (e) { /* silencioso */ }
}

const SORT_MODES = [
  { label: 'Más cotizados',   icon: 'fa-fire',        active: true  },
  { label: 'Menos cotizados', icon: 'fa-fire-flame-simple', active: true  },
  { label: 'Orden original',  icon: 'fa-list',        active: false }
];

function updateSortBtn() {
  const btn = document.getElementById('btnSortPopular');
  if (!btn) return;
  const mode = SORT_MODES[sortRankingMode];
  btn.innerHTML = `<i class="fas ${mode.icon}"></i> ${mode.label}`;
  btn.classList.toggle('active', mode.active);
}

async function toggleSortByPopular() {
  sortRankingMode = (sortRankingMode + 1) % 3;
  updateSortBtn();
  if (sortRankingMode !== 2 && Object.keys(acRankings).length === 0) {
    await loadRankings();
  }
  filterAC();
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init);
} else {
  init();
}

