function renderBrandFilterOptions() {
  const brandSelect = document.getElementById('filterBrand');
  if (!brandSelect) return;

  const selected = brandSelect.value;
  const brands = [...new Set(
    allAC
      .map(ac => (ac.marca || '').trim())
      .filter(Boolean)
  )].sort((a, b) => a.localeCompare(b, 'es'));

  brandSelect.innerHTML = '<option value="">Todas las marcas</option>' +
    brands.map(brand => `<option value="${brand}">${brand}</option>`).join('');

  if (selected && brands.includes(selected)) {
    brandSelect.value = selected;
  }
}

function normalizeBrandKey(brand) {
  return (brand || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

function getBrandIconCandidates(brand) {
  const normalized = normalizeBrandKey(brand);
  if (!normalized) return [];

  const baseNames = BRAND_ICON_OVERRIDES[normalized] || [normalized];
  const files = [];

  baseNames.forEach(base => {
    BRAND_ICON_EXTENSIONS.forEach(ext => {
      files.push(`${BRAND_ICON_DIR}/${base}.${ext}`);
    });
  });

  return [...new Set(files)];
}

function renderBrandLogo(brand) {
  const candidates = getBrandIconCandidates(brand);
  if (!candidates.length) return '';

  const brandKey = normalizeBrandKey(brand);

  return `<img class="ac-brand-logo" src="${candidates[0]}" alt="${brand || 'Marca'}" loading="lazy" data-brand-key="${brandKey}" data-candidates="${candidates.join('|')}" data-candidate-index="0" onerror="handleBrandIconError(this)">`;
}

function handleBrandIconError(img) {
  if (!img) return;

  const candidates = (img.dataset.candidates || '').split('|').filter(Boolean);
  const currentIndex = Number(img.dataset.candidateIndex || '0');
  const nextIndex = currentIndex + 1;

  if (nextIndex >= candidates.length) {
    img.style.display = 'none';
    return;
  }

  img.dataset.candidateIndex = String(nextIndex);
  img.src = candidates[nextIndex];
}
window.handleBrandIconError = handleBrandIconError;

// ============================================================
// RENDER AC GRID
// ============================================================
function renderACGrid() {
  try {
  const grid = document.getElementById('acGrid');
  const count = document.getElementById('resultsCount');
  if (!grid) return;
  if (filteredAC.length === 0) {
    grid.innerHTML = `<div class="empty-state"><div class="empty-icon"><i class="fas fa-magnifying-glass"></i></div><p>No se encontraron equipos con esos filtros.</p></div>`;
    if (count) count.innerHTML = '';
    return;
  }
  if (count) count.innerHTML = `<span>${filteredAC.length}</span> equipo${filteredAC.length!==1?'s':''} encontrado${filteredAC.length!==1?'s':''}`;
  grid.innerHTML = filteredAC.map((ac, idx) => {
    const origIdx = allAC.indexOf(ac);
    const selectedItems = (ac.capacities || [])
      .map(c => ({ btu: Number(c.btu_capacity), qty: selectedEquipments[equipKey(origIdx, Number(c.btu_capacity))] || 0, cap: c }))
      .filter(item => item.qty > 0);
    const isSelected = selectedItems.length > 0;
    const brand = (ac.marca || '').trim();
    const brandLogo = renderBrandLogo(brand);
    const displayName = brand ? `${ac.brand_model}` : ac.brand_model;
    const refBadge = ac.refrigerant === 'R32' ? 'badge-r32' : 'badge-r410';
    const wifiLabel = ac.wifi === 'Yes' ? 'WiFi incluido' : ac.wifi === 'Optional' ? 'WiFi opcional' : 'WiFi universal';
    const warYears = ac.warranty && ac.warranty.includes('3') ? 'Garantia 3 anos' : 'Garantia 1 ano';
    const kitLabel = `Kit de instalacion ${ac.installation_kit}`;
    const rankCount = window.RankingRepo ? (acRankings[window.RankingRepo.modelKey(ac.brand_model)] || 0) : 0;
    const rankBadge = (sortRankingMode !== 2 && rankCount > 0)
      ? `<span class="ranking-badge"><i class="fas fa-fire"></i> ${rankCount}</span>`
      : '';
    return `
    <div class="ac-card ${isSelected ? 'selected' : ''}" id="accard-${origIdx}">
      <div class="ac-header">
        <div>
          <div class="ac-brand-row">
            ${brandLogo}
          </div>
          <div class="ac-brand">${displayName}</div>
          <div class="ac-type">${ac.type}</div>
        </div>
        <div style="display:flex;flex-direction:column;align-items:flex-end;gap:4px;">
          <span class="ac-badge ${refBadge}">${ac.refrigerant}</span>
          ${rankBadge}
        </div>
      </div>
      <div class="btu-label">Capacidad BTU</div>
      <div class="btu-options">
        ${ac.capacities.map(c => `
          <button class="btu-btn ${(selectedEquipments[equipKey(origIdx, Number(c.btu_capacity))] || 0) > 0 ? 'selected' : ''}"
            onclick="selectAC(${origIdx}, ${c.btu_capacity}); event.stopPropagation()">
            ${(c.btu_capacity/1000).toFixed(0)}K${(selectedEquipments[equipKey(origIdx, Number(c.btu_capacity))] || 0) > 0 ? ` x${selectedEquipments[equipKey(origIdx, Number(c.btu_capacity))] || 0}` : ''}
          </button>
        `).join('')}
      </div>
      <div class="ac-specs" aria-label="Especificaciones">
        <span class="spec-tag icon-only wifi" title="${wifiLabel}" aria-label="${wifiLabel}"><i class="fas fa-wifi"></i></span>
        <span class="spec-tag icon-only warranty" title="${warYears}" aria-label="${warYears}"><i class="fas fa-shield-halved"></i></span>
        <span class="spec-tag icon-only" title="${kitLabel}" aria-label="${kitLabel}"><i class="fas fa-box"></i></span>
      </div>
      ${isSelected ? renderACPrice(origIdx) : ''}
    </div>`;
  }).join('');
  } catch(err) {
    const grid = document.getElementById('acGrid');
    if (grid) grid.innerHTML = `<div class="empty-state"><div class="empty-icon"><i class="fas fa-triangle-exclamation"></i></div><p>Error al cargar: ${err.message}</p></div>`;
  }
}

function renderACPrice(idx) {
  const ac = allAC[idx];
  const selectedItems = (ac.capacities || [])
    .map(c => ({ btu: Number(c.btu_capacity), qty: selectedEquipments[equipKey(idx, Number(c.btu_capacity))] || 0, cap: c }))
    .filter(item => item.qty > 0);
  if (!selectedItems.length) return '';

  const detailRows = selectedItems.map(item => {
    const subtotal = item.cap.price_with_tax * item.qty;
    return `<div style="font-size:11px;color:var(--text-dim);margin-bottom:4px;display:flex;justify-content:space-between;align-items:center;gap:8px;">
      <span>${(item.btu/1000).toFixed(0)}K x ${item.qty}</span>
      <span style="display:flex;align-items:center;gap:4px;">
        <button class="btu-btn" style="padding:2px 7px;" onclick="changeEquipmentQty(${idx}, ${item.btu}, -1); event.stopPropagation()">-</button>
        <button class="btu-btn" style="padding:2px 7px;" onclick="changeEquipmentQty(${idx}, ${item.btu}, 1); event.stopPropagation()">+</button>
      </span>
      <span style="font-family:'DM Mono',monospace;color:var(--accent);">$${fmtNum(subtotal)}</span>
    </div>`;
  }).join('');

  const total = selectedItems.reduce((sum, item) => sum + item.cap.price_with_tax * item.qty, 0);
  return `
    <div class="ac-price">
      <div style="width:100%;">
        ${detailRows}
        <div style="display:flex;justify-content:space-between;align-items:center;border-top:1px solid var(--border);padding-top:6px;">
          <div class="price-net">Total equipo</div>
          <div class="price-iva">$${fmtNum(total)} <span>c/IVA</span></div>
        </div>
      </div>
    </div>`;
}

function selectAC(idx, btu) {
  const key = equipKey(idx, Number(btu));
  selectedEquipments[key] = (selectedEquipments[key] || 0) + 1;
  selectedAC = idx;
  selectedBTU = btu;
  updateStep1NextButton();
  renderACGrid();
  showToast(`${allAC[idx].brand_model} · ${(btu/1000).toFixed(0)}K (x${selectedEquipments[key]})`, 'success');
}

function changeEquipmentQty(idx, btu, delta) {
  const key = equipKey(idx, Number(btu));
  const nextQty = Math.max(0, (selectedEquipments[key] || 0) + delta);
  if (nextQty === 0) {
    delete selectedEquipments[key];
  } else {
    selectedEquipments[key] = nextQty;
  }
  updateStep1NextButton();
  renderACGrid();
}

function filterAC() {
  const search = document.getElementById('searchInput').value.toLowerCase();
  const brand = document.getElementById('filterBrand').value;
  const btu = parseInt(document.getElementById('filterBTU').value) || 0;
  const ref = document.getElementById('filterRef').value;
  // const warranty = document.getElementById('filterWarranty').value;
  // const wifi = document.getElementById('filterWifi').value;

  filteredAC = allAC.filter(ac => {
    const brandName = (ac.marca || '').toLowerCase();
    const modelName = (ac.brand_model || '').toLowerCase();
    if (search && !brandName.includes(search) && !modelName.includes(search)) return false;
    if (brand && (ac.marca || '') !== brand) return false;
    if (ref && ac.refrigerant !== ref) return false;
    // if (wifi && ac.wifi !== wifi) return false;
    // if (warranty === '1' && !ac.warranty.includes('1')) return false;
    // if (warranty === '3' && !ac.warranty.includes('3')) return false;
    if (btu && !ac.capacities.find(c => c.btu_capacity === btu)) return false;
    return true;
  });

  if (sortRankingMode !== 2 && window.RankingRepo) {
    filteredAC.sort((a, b) => {
      const aCount = acRankings[window.RankingRepo.modelKey(a.brand_model)] || 0;
      const bCount = acRankings[window.RankingRepo.modelKey(b.brand_model)] || 0;
      return sortRankingMode === 0 ? bCount - aCount : aCount - bCount;
    });
  }

  renderACGrid();
}

// ============================================================
// RENDER SERVICE GRID
// ============================================================
function renderServiceGrid() {
  const equipCount = getEquipCount();
  document.getElementById('serviceGrid').innerHTML = SERVICES.map(s => {
    const qty = Math.max(0, serviceQtyMap[s.id] || 0);
    const isActive = isMultiService(s.id) ? qty > 0 : selectedService === s.id;
    const atInstCap = s.id === 'instalacion' && equipCount > 0 && qty >= equipCount;

    let displayPrice;
    if (s.id === 'reparacion') displayPrice = repairQty * repairUnitValue;
    else if (s.id === 'instalacion') displayPrice = qty * instalacionUnitValue;
    else if (s.id === 'mantencion') displayPrice = qty * mantencionUnitValue;
    else if (isMultiService(s.id)) displayPrice = qty * s.price;
    else displayPrice = s.price;

    const priceHtml = displayPrice > 0
      ? `$${fmtNum(displayPrice)}`
      : (isMultiService(s.id) ? `<span class="svc-tap-hint">toca para agregar</span>` : 'Sin costo');

    const topStyle = atInstCap ? ' style="pointer-events:none"' : '';

    let inlineControls = '';
    if (isMultiService(s.id) && isActive) {
      const plusDisabled = atInstCap ? 'disabled' : '';
      const unitHtml = s.id === 'instalacion' ? `
        <div class="svc-unit-row">
          <div class="svc-unit-label">Valor por instalación</div>
          <input type="number" class="svc-unit-input" value="${instalacionUnitValue}"
            min="0" step="1000" oninput="updateInstalacionValueInline(this.value)">
        </div>` : s.id === 'mantencion' ? `
        <div class="svc-unit-row">
          <div class="svc-unit-label">Valor por mantención</div>
          <input type="number" class="svc-unit-input" value="${mantencionUnitValue}"
            min="0" step="1000" oninput="updateMantencionValueInline(this.value)">
        </div>` : '';
      inlineControls = `
        <div class="svc-inline-controls">
          <div class="svc-counter">
            <button class="svc-counter-btn" onclick="decrementService('${s.id}')">&#8722;</button>
            <span class="svc-counter-val">${qty}</span>
            <button class="svc-counter-btn" onclick="selectService('${s.id}')" ${plusDisabled}>+</button>
          </div>${unitHtml}
        </div>`;
    } else if (s.id === 'reparacion' && isActive) {
      inlineControls = `
        <div class="svc-inline-controls">
          <div class="svc-repair-row">
            <div class="svc-repair-field">
              <div class="svc-unit-label">Cantidad</div>
              <input type="number" id="repairQty" class="svc-unit-input" value="${repairQty}"
                min="1" step="1" oninput="updateRepairServiceValue()">
            </div>
            <div class="svc-repair-field">
              <div class="svc-unit-label">Valor unitario</div>
              <input type="number" id="repairUnitValue" class="svc-unit-input" value="${repairUnitValue}"
                min="0" step="1000" oninput="updateRepairServiceValue()">
            </div>
          </div>
        </div>`;
    }

    return `
    <div class="service-card ${isActive ? 'selected' : ''}" id="svc-card-${s.id}">
      <div class="svc-card-top" onclick="selectService('${s.id}')"${topStyle}>
        <div class="service-icon"><i class="fas ${s.icon}"></i></div>
        <div class="service-name">${s.name}${atInstCap ? ' <span class="svc-cap-hint">máx</span>' : ''}</div>
        <div class="service-price" id="svc-price-${s.id}">${priceHtml}</div>
      </div>
      ${inlineControls}
    </div>`;
  }).join('');
}

function isMultiService(id) {
  return id === 'instalacion' || id === 'mantencion';
}

function updateStep2NextButton() {
  const btn = document.getElementById('btnStep2Next');
  if (!btn) return;
  const hasMulti = (serviceQtyMap.instalacion || 0) > 0 || (serviceQtyMap.mantencion || 0) > 0;
  const hasSingle = !!selectedService;
  const enabled = hasMulti || hasSingle;
  btn.disabled = !enabled;
  btn.style.opacity = enabled ? '1' : '0.4';
}

function selectService(id) {
  if (isMultiService(id)) {
    if (id === 'instalacion') {
      const equipCount = getEquipCount();
      if (equipCount > 0 && (serviceQtyMap.instalacion || 0) >= equipCount) return;
    }
    serviceQtyMap[id] = Math.max(0, (serviceQtyMap[id] || 0) + 1);
    updateMultiServiceInputs();
    renderServiceGrid();
    updateStep2NextButton();
    buildSummary();
    return;
  }

  selectedService = selectedService === id ? null : id;
  toggleRepairInputs();
  renderServiceGrid();
  updateStep2NextButton();
  buildSummary();
}

function decrementService(id) {
  if (!isMultiService(id)) return;
  serviceQtyMap[id] = Math.max(0, (serviceQtyMap[id] || 0) - 1);
  updateMultiServiceInputs();
  renderServiceGrid();
  updateStep2NextButton();
  buildSummary();
}

function updateMultiServiceInputs() {
  updateServiceQtyPreview();
}

function updateServiceQtyPreview() {
  const preview = document.getElementById('serviceQtyPreview');
  if (!preview) return;
  const mantSvc = SERVICES.find(s => s.id === 'mantencion');
  const parts = [];
  const instQty = serviceQtyMap.instalacion || 0;
  const mantQty = serviceQtyMap.mantencion || 0;
  if (instQty > 0) parts.push(`${instQty} instalación${instQty !== 1 ? 'es' : ''} · $${fmtNum(instQty * instalacionUnitValue)}`);
  if (mantQty > 0) parts.push(`${mantQty} mantención${mantQty !== 1 ? 'es' : ''} · $${fmtNum(mantQty * mantencionUnitValue)}`);
  preview.textContent = parts.join('   |   ');
  preview.style.display = parts.length ? 'block' : 'none';
}

function updateInstalacionValueInline(val) {
  instalacionUnitValue = Math.max(0, parseFloat(val) || 0);
  const qty = serviceQtyMap.instalacion || 0;
  const priceEl = document.getElementById('svc-price-instalacion');
  if (priceEl) priceEl.textContent = qty > 0 ? `$${fmtNum(qty * instalacionUnitValue)}` : '';
  updateServiceQtyPreview();
  buildSummary();
}

function updateMantencionValueInline(val) {
  mantencionUnitValue = Math.max(0, parseFloat(val) || 0);
  const qty = serviceQtyMap.mantencion || 0;
  const priceEl = document.getElementById('svc-price-mantencion');
  if (priceEl) priceEl.textContent = qty > 0 ? `$${fmtNum(qty * mantencionUnitValue)}` : '';
  updateServiceQtyPreview();
  buildSummary();
}

function updateServiceQtyValue() {
  // Mantención qty is now set directly in state (no DOM input).
  // Called from importQuoteSnapshot for backwards compat.
  updateMultiServiceInputs();
  renderServiceGrid();
  updateStep2NextButton();
}

function toggleRepairInputs() {
  // Repair inputs are now rendered inline inside the service card.
}

function updateRepairServiceValue() {
  const qtyEl = document.getElementById('repairQty');
  const unitEl = document.getElementById('repairUnitValue');
  repairQty = Math.max(1, parseInt((qtyEl && qtyEl.value) || '1', 10) || 1);
  repairUnitValue = Math.max(0, parseFloat((unitEl && unitEl.value) || '0') || 0);
  // Update price display directly without re-rendering grid (avoids losing input focus)
  const priceEl = document.getElementById('svc-price-reparacion');
  if (priceEl) priceEl.textContent = `$${fmtNum(repairQty * repairUnitValue)}`;
  buildSummary();
  recalcTotal();
}

function getCurrentServiceValues(svc) {
  if (!svc) return { qty: 0, unitPrice: 0, totalPrice: 0 };
  if (svc.id === 'reparacion') {
    const qty = Math.max(1, repairQty || 1);
    const unitPrice = Math.max(0, repairUnitValue || 0);
    return { qty, unitPrice, totalPrice: qty * unitPrice };
  }
  return { qty: 1, unitPrice: svc.price, totalPrice: svc.price };
}

function getSelectedServiceItems() {
  const items = [];

  ['instalacion', 'mantencion'].forEach(id => {
    const svc = SERVICES.find(s => s.id === id);
    const qty = Math.max(0, serviceQtyMap[id] || 0);
    if (svc && qty > 0) {
      const unitPrice = id === 'instalacion' ? instalacionUnitValue
                       : id === 'mantencion' ? mantencionUnitValue
                       : svc.price;
      items.push({ svc, qty, unitPrice, totalPrice: qty * unitPrice });
    }
  });

  if (selectedService && !isMultiService(selectedService)) {
    const svc = SERVICES.find(s => s.id === selectedService);
    if (svc) {
      const current = getCurrentServiceValues(svc);
      if (current.totalPrice > 0 || svc.price === 0) {
        items.push({ svc, qty: current.qty, unitPrice: current.unitPrice, totalPrice: current.totalPrice });
      }
    }
  }

  return items;
}

// ============================================================
// RENDER ACCESSORIES
// ============================================================
// Maps accessory IDs (and fallback categories) to Font Awesome icon classes.
// Edit this object to change any icon without touching Firebase.
const ACC_ICON_MAP = {
  // By ID (takes priority)
  kit_can_9k:        'fa-ruler-combined',
  kit_can_12_18k:    'fa-ruler-combined',
  kit_can_24k:       'fa-ruler-combined',
  cordon_15:         'fa-bolt',
  cordon_25:         'fa-bolt',
  soporte_techo:     'fa-thumbtack',
  kit_drenaje:       'fa-droplet',
  breaker_16a:       'fa-plug',
  mantencion_lavado: 'fa-spray-can-sparkles',
  gas_r410_12k:      'fa-temperature-low',
  gas_r410_18_32k:   'fa-temperature-low',
  gas_r32_12k:       'fa-temperature-low',
  gas_r32_18_32k:    'fa-temperature-low',
  // Fallback by category
  _cat_cañerias:     'fa-ruler-combined',
  _cat_electrico:    'fa-bolt',
  _cat_instalacion:  'fa-screwdriver-wrench',
  _cat_mantencion:   'fa-spray-can-sparkles',
  _cat_gas:          'fa-temperature-low',
};

function getAccIcon(acc) {
  return ACC_ICON_MAP[acc.id]
    || ACC_ICON_MAP['_cat_' + (acc.categoria || '')]
    || 'fa-box';
}

function renderAccGrid() {
  document.getElementById('accGrid').innerHTML = ACCESSORIES.map(acc => `
    <div class="acc-card">
      <div class="acc-icon" style="background:${acc.color}"><i class="fas ${getAccIcon(acc)}"></i></div>
      <div class="acc-info">
        <div class="acc-name">${acc.name}</div>
        <div class="acc-desc">${acc.desc}</div>
      </div>
      <div>
        <div class="acc-price-tag">$${fmtNum(acc.price)}<small>c/u</small></div>
        <div class="qty-control" style="margin-top:6px">
          <button class="qty-btn" onclick="changeQty('${acc.id}', -1)">−</button>
          <input class="qty-val" id="qty-${acc.id}" value="${accQty[acc.id]||0}" readonly>
          <button class="qty-btn" onclick="changeQty('${acc.id}', 1)">+</button>
        </div>
      </div>
    </div>
  `).join('');
}

function changeQty(id, delta) {
  accQty[id] = Math.max(0, (accQty[id] || 0) + delta);
  document.getElementById('qty-'+id).value = accQty[id];
  updateAccSummary();
}

function updateAccSummary() {
  let total = 0, count = 0;
  ACCESSORIES.forEach(acc => {
    const q = accQty[acc.id] || 0;
    if (q > 0) { total += acc.price * q; count += q; }
  });
  const chip = document.getElementById('accSummaryChip');
  if (count > 0) {
    chip.style.display = 'block';
    document.getElementById('accSummaryText').textContent = `${count} ítem${count!==1?'s':''}`;
    document.getElementById('accSummaryPrice').textContent = '$'+fmtNum(total);
  } else {
    chip.style.display = 'none';
  }
}

// ============================================================
// STEP NAVIGATION
// ============================================================
function goToStep(n) {
  for (let i=1; i<=5; i++) {
    document.getElementById('page'+i).classList.toggle('active', i===n);
    document.getElementById('nav'+i).classList.toggle('active', i===n);
    const dot = document.getElementById('sd'+i);
    const lbl = document.getElementById('sl'+i);
    dot.className = 'step-dot ' + (i < n ? 'done' : i === n ? 'active' : '');
    lbl.className = 'step-label ' + (i < n ? 'done' : i === n ? 'active' : '');
    dot.textContent = i < n ? '✓' : i;
    if (i < 5) {
      document.getElementById('sline'+i).className = 'step-line ' + (i < n ? 'done' : '');
    }
  }
  currentStep = n;
  window.currentStep = currentStep;
  if (n === 2) {
    preloadInstallationsFromEquipment();
    renderServiceChip();
  }
  if (n === 1 && sortRankingMode !== 2) {
    loadRankings().then(() => filterAC());
  }
  window.scrollTo(0,0);
}

function renderServiceChip() {
  const chip = document.getElementById('acSelectionChip');
  const selectedItems = getSelectedEquipmentItems();
  if (!selectedItems.length) { chip.innerHTML = ''; return; }
  const equipCount = selectedItems.reduce((sum, item) => sum + item.qty, 0);
  const equipTotal = selectedItems.reduce((sum, item) => sum + (item.cap.price_with_tax * item.qty), 0);
  chip.innerHTML = `
    <div class="selection-chip">
      <div class="chip-icon"><i class="fas fa-snowflake"></i></div>
      <div class="chip-info">
        <div class="chip-title">Equipos seleccionados: ${equipCount}</div>
        <div class="chip-sub">${selectedItems.slice(0, 2).map(item => `${item.ac.marca ? item.ac.marca + ' ' : ''}${item.ac.brand_model} ${(item.btu/1000).toFixed(0)}K x${item.qty}`).join(' · ')}${selectedItems.length > 2 ? ' ...' : ''}</div>
      </div>
      <div>
        <div class="chip-price">$${fmtNum(equipTotal)}</div>
        <button class="chip-edit-btn" onclick="goToStep(1)">Cambiar</button>
      </div>
    </div>`;
}

// ============================================================
// BUILD SUMMARY
// ============================================================
function buildSummary() {
  const selectedEquipItems = getSelectedEquipmentItems();
  const selectedServiceItems = getSelectedServiceItems();

  // Quote info
  document.getElementById('sumQuoteNum').textContent = quoteNumber;
  document.getElementById('sumDate').textContent = new Date().toLocaleDateString('es-CL', {day:'2-digit',month:'long',year:'numeric'});

  // Client
  const name = document.getElementById('clientName').value || '—';
  const rut = document.getElementById('clientRut').value;
  const phone = document.getElementById('clientPhone').value || '—';
  const address = document.getElementById('clientAddress').value || '—';
  const city = document.getElementById('clientCity').value || '';
  const region = document.getElementById('clientRegion').value || '';
  document.getElementById('sumClientName').textContent = name;
  document.getElementById('sumClientRut').textContent = rut || '—';
  document.getElementById('sumRutRow').style.display = rut ? 'flex' : 'none';
  document.getElementById('sumClientPhone').textContent = phone;
  document.getElementById('sumClientAddress').textContent = `${address}${city?', '+city:''}${region?', '+region:''}`;

  // Equipment
  if (selectedEquipItems.length > 0) {
    const modelTxt = selectedEquipItems
      .map(item => `${item.ac.marca ? item.ac.marca + ' ' : ''}${item.ac.brand_model} ${(item.btu/1000).toFixed(0)}K x${item.qty}`)
      .join(' + ');
    const btuTxt = selectedEquipItems
      .map(item => `${(item.btu/1000).toFixed(0)}K x${item.qty}`)
      .join(' + ');
    const refs = [...new Set(selectedEquipItems.map(item => item.ac.refrigerant))].join(', ');
    document.getElementById('sumEquipModel').textContent = modelTxt;
    document.getElementById('sumEquipBtu').textContent = btuTxt;
    document.getElementById('sumEquipRef').textContent = refs;
    document.getElementById('sumEquipPrice').value = getEquipmentTotalPrice();
  } else {
    document.getElementById('sumEquipModel').textContent = 'Sin equipo';
    document.getElementById('sumEquipPrice').value = 0;
  }

  // Service
  if (selectedServiceItems.length > 0) {
    const serviceLabel = selectedServiceItems
      .map(item => `${item.svc.name} (${item.qty} x $${fmtNum(item.unitPrice)})`)
      .join(' + ');
    const serviceTotal = selectedServiceItems.reduce((acc, item) => acc + item.totalPrice, 0);
    document.getElementById('sumServiceName').textContent = serviceLabel;
    document.getElementById('sumServicePrice').value = serviceTotal;
    const notes = document.getElementById('serviceNotes').value;
    if (notes) {
      document.getElementById('sumNotesRow').style.display = 'flex';
      document.getElementById('sumNotes').textContent = notes;
    } else {
      document.getElementById('sumNotesRow').style.display = 'none';
    }
  } else {
    document.getElementById('sumServiceName').textContent = '—';
    document.getElementById('sumServicePrice').value = 0;
  }

  // Extras
  const extrasCard = document.getElementById('sumExtrasCard');
  const extrasList = document.getElementById('sumExtrasList');
  const activeExtras = ACCESSORIES.filter(acc => (accQty[acc.id]||0) > 0);
  if (activeExtras.length > 0) {
    extrasCard.style.display = 'block';
    extrasList.innerHTML = activeExtras.map(acc => {
      const q = accQty[acc.id];
      const subtotal = acc.price * q;
      return `<div class="summary-row">
        <div class="summary-row-label">${acc.name} × ${q}</div>
        <div class="summary-row-val">$${fmtNum(subtotal)}</div>
      </div>`;
    }).join('');
  } else {
    extrasCard.style.display = 'none';
  }

  recalcTotal();
}

function recalcTotal() {
  const equipPrice = parseFloat(document.getElementById('sumEquipPrice').value) || 0;
  const servicePrice = parseFloat(document.getElementById('sumServicePrice').value) || 0;
  let extrasTotal = 0;
  ACCESSORIES.forEach(acc => {
    extrasTotal += (accQty[acc.id]||0) * acc.price;
  });
  const subtotal = equipPrice + servicePrice + extrasTotal;
  const discPct = parseFloat(document.getElementById('discountPct').value) || 0;
  const discAmt = subtotal * discPct / 100;
  const total = subtotal - discAmt;
  document.getElementById('discountBadgeAmt').textContent = `−$${fmtNum(Math.round(discAmt))}`;
  document.getElementById('grandTotal').textContent = fmtNum(Math.round(total));
}

// ============================================================
// PDF GENERATION
// ============================================================
async function buildPDFDoc() {
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

  const pageW = 210, margin = 18;
  let y = 0;

  const headerH = 28;
  const headerBottomGap = 8;
  const titleY = 13 + 5;
  const subtitleY = titleY + 3;
  const metaY1 = 10;
  const metaY2 = 15;
  const metaY3 = 20;

  doc.setFillColor(242, 244, 247);
  doc.rect(0, 0, pageW, headerH, 'F');
  doc.setFillColor(79, 102, 132);
  doc.rect(0, 0, 4, headerH, 'F');

  const logoSize = 20;
  const logoX = 18;
  const logoY = ((titleY + 13) / 2) - (logoSize / 2);

  let titleX = 14;
  const logoSource = await getPdfLogoSource();
  if (logoSource) {
    doc.addImage(logoSource, 'PNG', logoX, logoY, logoSize, logoSize, undefined, 'NONE');
    titleX = logoX + logoSize + 4;
  }

  doc.setTextColor(33, 37, 41);
  doc.setFontSize(20);
  doc.setFont('helvetica', 'bold');
  doc.text('RefriPro Climatización', titleX, titleY);

  doc.setTextColor(92, 99, 112);
  doc.setFontSize(8);
  doc.setFont('helvetica', 'normal');
  doc.text('"Controlamos el Clima"', titleX, subtitleY);

  doc.setTextColor(106, 112, 124);
  doc.setFontSize(7.5);
  doc.text(document.getElementById('sumQuoteNum').textContent, pageW - margin, metaY1, { align: 'right' });
  doc.text(document.getElementById('sumDate').textContent, pageW - margin, metaY2, { align: 'right' });
  doc.setTextColor(80, 86, 98);
  doc.text('Válido por 15 días', pageW - margin, metaY3, { align: 'right' });

  y = headerH + headerBottomGap;

  // CLIENT SECTION
  const clientName = document.getElementById('clientName').value || '—';
  const clientRut = document.getElementById('clientRut').value || '';
  const clientPhone = document.getElementById('clientPhone').value || '—';
  const clientEmail = document.getElementById('clientEmail').value || '';
  const clientAddress = document.getElementById('clientAddress').value || '—';
  const clientCity = document.getElementById('clientCity').value || '';
  const clientRegion = document.getElementById('clientRegion').value || '';
  const clientProperty = document.getElementById('clientProperty').value || '';

  sectionHeader(doc, '  DATOS DEL CLIENTE', margin, y, pageW - margin*2);
  y += 10;

  const clientData = [
    ['Nombre', clientName],
    ...(clientRut ? [['RUT', clientRut]] : []),
    ['Teléfono', clientPhone],
    ...(clientEmail ? [['Email', clientEmail]] : []),
    ['Dirección', `${clientAddress}${clientCity?', '+clientCity:''}${clientRegion?', '+clientRegion:''}`],
    ...(clientProperty ? [['Inmueble', clientProperty]] : []),
  ];
  clientData.forEach(([label, val]) => {
    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(73, 89, 114);
    doc.text(label + ':', margin + 2, y);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(31, 41, 55);
    doc.text(val, margin + 35, y);
    y += 6;
  });
  y += 4;

  // EQUIPMENT
  const selectedEquipItems = getSelectedEquipmentItems();
  const selectedServiceItems = getSelectedServiceItems();
  const activeExtras = ACCESSORIES.filter(acc => (accQty[acc.id]||0) > 0);

  sectionHeader(doc, '  DETALLE EQUIPOS Y SERVICIOS', margin, y, pageW - margin*2);
  y += 8;

  const tableBody = [];

  selectedEquipItems.forEach(item => {
    tableBody.push([
      `${item.ac.brand_model}\n${item.ac.type} · ${item.ac.refrigerant} · Kit ${item.ac.installation_kit}`,
      `${(item.btu/1000).toFixed(0)}.000 BTU`,
      String(item.qty),
      `$${fmtNum(item.cap.net_price)}`,
      `$${fmtNum(item.cap.price_with_tax * item.qty)}`
    ]);
  });

  selectedServiceItems.forEach(item => {
    const serviceDesc = `${item.svc.name}\n${item.svc.desc} · ${item.qty} x $${fmtNum(item.unitPrice)}`;
    tableBody.push([
      serviceDesc,
      'Servicio',
      String(item.qty),
      item.totalPrice > 0 ? `$${fmtNum(Math.round(item.totalPrice/1.19))}` : '$0',
      item.totalPrice > 0 ? `$${fmtNum(item.totalPrice)}` : 'Sin costo'
    ]);
  });

  activeExtras.forEach(acc => {
    const q = accQty[acc.id];
    tableBody.push([
      `${acc.name}\n${acc.desc}`,
      'Accesorio',
      String(q),
      `$${fmtNum(acc.price)}`,
      `$${fmtNum(acc.price * q)}`
    ]);
  });

  const tableContentWidth = pageW - (margin * 2);

  doc.autoTable({
    startY: y,
    head: [['DESCRIPCIÓN', 'TIPO', 'CANT.', 'P. NETO', 'P. c/IVA']],
    body: tableBody,
    margin: { left: margin, right: margin },
    tableWidth: tableContentWidth,
    styles: { fontSize: 8, font: 'helvetica', cellPadding: 4, textColor: [61, 66, 77] },
    headStyles: {
      fillColor: [31, 53, 82],
      textColor: [255, 255, 255],
      fontStyle: 'bold',
      fontSize: 8
    },
    alternateRowStyles: { fillColor: [247, 248, 250] },
    columnStyles: {
      // 174 total = 82 + 22 + 14 + 28 + 28
      0: { cellWidth: 82 },
      1: { cellWidth: 22, halign: 'center' },
      2: { cellWidth: 14, halign: 'center' },
      3: { cellWidth: 28, halign: 'right' },
      4: { cellWidth: 28, halign: 'right', fontStyle: 'bold' }
    },
  });

  y = doc.lastAutoTable.finalY + 8;

  // TOTALS
  const equipP = parseFloat(document.getElementById('sumEquipPrice').value) || 0;
  const svcP = parseFloat(document.getElementById('sumServicePrice').value) || 0;
  let extrasP = 0;
  ACCESSORIES.forEach(acc => { extrasP += (accQty[acc.id]||0) * acc.price; });
  const subtotal = equipP + svcP + extrasP;
  const discPct = parseFloat(document.getElementById('discountPct').value) || 0;
  const discAmt = subtotal * discPct / 100;
  const total = subtotal - discAmt;

  const totX = pageW - margin - 70;
  const totW = 70;
  const rowH = 8;       // height of each text row
  const pad  = 5;       // top padding inside the bg rect
  const rowCount = discPct > 0 ? 2 : 1;  // subtotal [+ discount]
  const bgH  = rowCount * rowH + pad * 2;

  doc.setFillColor(244, 245, 247);
  doc.rect(totX, y, totW, bgH, 'F');

  doc.setFontSize(8.5);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(97, 103, 115);

  const row1Y = y + pad + rowH - 2;
  doc.text('Subtotal:', totX + 4, row1Y);
  doc.text(`$${fmtNum(Math.round(subtotal))}`, totX + totW - 4, row1Y, { align: 'right' });

  if (discPct > 0) {
    const row2Y = row1Y + rowH;
    doc.setTextColor(139, 46, 15);
    doc.text(`Descuento (${discPct}%):`, totX + 4, row2Y);
    doc.text(`$${fmtNum(Math.round(discAmt))}`, totX + totW - 4, row2Y, { align: 'right' });
  }

  y += bgH + 2;

  doc.setFillColor(31, 53, 82);
  doc.rect(totX, y, totW, 11, 'F');
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(10);
  doc.text('TOTAL:', totX + 4, y + 7.5);
  doc.text(`$${fmtNum(Math.round(total))}`, totX + totW - 4, y + 7.5, { align: 'right' });

  y += 11 + 10;

  // SERVICE NOTES
  const notes = document.getElementById('serviceNotes').value;
  if (notes) {
    doc.setFontSize(8);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(73, 89, 114);
    doc.text('Observaciones:', margin, y);
    y += 5;
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(52, 64, 84);
    const lines = doc.splitTextToSize(notes, pageW - margin*2);
    doc.text(lines, margin, y);
    y += lines.length * 4 + 6;
  }

  // CLIENT NOTES
  const clientNotes = document.getElementById('clientNotes').value;
  if (clientNotes) {
    doc.setFontSize(8);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(73, 89, 114);
    doc.text('Notas adicionales:', margin, y);
    y += 5;
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(52, 64, 84);
    const lines = doc.splitTextToSize(clientNotes, pageW - margin*2);
    doc.text(lines, margin, y);
    y += lines.length * 4 + 6;
  }

  // INFORMACION RELEVANTE Y EXTRA SEGUN SERVICIO
  y = appendServiceInfoToPdf(doc, y, margin, pageW, selectedServiceItems);

  // FOOTER
  const pageH = 297;
  doc.setFillColor(31, 53, 82);
  doc.rect(0, pageH - 18, pageW, 18, 'F');
  doc.setFillColor(79, 102, 132);
  doc.rect(0, pageH - 18, 4, 18, 'F');
  doc.setFontSize(7.5);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(226, 229, 235);
  doc.text('RefriPro · Generado con CotizaClima App', margin + 4, pageH - 9);
  doc.setTextColor(238, 240, 244);
  doc.text(quoteNumber, pageW - margin, pageH - 9, { align: 'right' });

  return doc;
}

async function generatePDF() {
  const doc = await buildPDFDoc();
  doc.save(`${quoteNumber}.pdf`);
  showToast('PDF generado correctamente', 'success');
}

async function sharePDF() {
  showToast('Generando PDF…', 'info');
  let doc;
  try {
    doc = await buildPDFDoc();
  } catch (e) {
    showToast('Error al generar el PDF', 'error');
    return;
  }
  const fileName = `${quoteNumber}.pdf`;
  const blob = doc.output('blob');
  const clientName = document.getElementById('clientName').value || '';
  const total = document.getElementById('grandTotal').textContent || '0';
  const quoteNum = document.getElementById('sumQuoteNum').textContent || quoteNumber;
  const shareText = `Cotización ${quoteNum} — ${clientName}\nTotal: $${total}`;
  const file = new File([blob], fileName, { type: 'application/pdf' });
  if (navigator.canShare && navigator.canShare({ files: [file] })) {
    try { await navigator.share({ title: fileName, text: shareText, files: [file] }); return; }
    catch (e) { if (e.name === 'AbortError') return; }
  }
  if (navigator.share) {
    try { await navigator.share({ title: fileName, text: shareText }); return; }
    catch (e) { if (e.name === 'AbortError') return; }
  }
  doc.save(fileName);
  showToast('PDF descargado', 'success');
}

let pdfLogoCache = null;

// Pega aqui tu PNG en base64.
// Puede ser:
// 1) Solo el base64 puro: iVBORw0KGgoAAA...
// 2) O el data URL completo: data:image/png;base64,iVBORw0KGgoAAA...
const PDF_LOGO_BASE64 = '';

function normalizePngDataUrl(input) {
  if (!input) return null;
  const raw = String(input).trim();

  if (!raw) return null;

  // Si ya viene como data URL completo, usarlo tal cual.
  if (raw.startsWith('data:image/png;base64,')) {
    return raw;
  }

  // Limpiar espacios/saltos por si copiaste base64 multilinea.
  const cleanBase64 = raw.replace(/\s+/g, '');
  return `data:image/png;base64,${cleanBase64}`;
}

async function getPdfLogoSource() {
  if (pdfLogoCache) return pdfLogoCache;

  const dataUrl = normalizePngDataUrl(PDF_LOGO_BASE64);
  if (!dataUrl) return null;

  pdfLogoCache = dataUrl;
  return dataUrl;
}

function sectionHeader(doc, text, x, y, w) {
  doc.setFillColor(31, 53, 82);
  doc.rect(x, y - 5, w, 8, 'F');
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(8);
  doc.setFont('helvetica', 'bold');
  doc.text(text, x + 2, y);
}

function ensurePdfSpace(doc, y, neededHeight, pageH = 297) {
  if (y + neededHeight <= pageH - 22) return y;
  doc.addPage();
  return 20;
}

function getServiceInfoKeys(selectedServiceItems) {
  const keys = new Set();
  selectedServiceItems.forEach(item => {
    const id = item && item.svc ? item.svc.id : '';
    if (!id) return;
    if (id === 'cambio') {
      keys.add('instalacion');
      return;
    }
    if (SERVICE_PDF_CONTENT[id]) {
      keys.add(id);
    }
  });
  return [...keys];
}

function appendServiceInfoToPdf(doc, startY, margin, pageW, selectedServiceItems) {
  const keys = getServiceInfoKeys(selectedServiceItems);
  if (!keys.length) return startY;

  let y = startY;
  const contentWidth = pageW - margin * 2;

  keys.forEach((key, idx) => {
    const block = SERVICE_PDF_CONTENT[key];
    if (!block) return;

    y = ensurePdfSpace(doc, y, 38);
    sectionHeader(doc, `  INFORMACION RELEVANTE Y EXTRA · ${block.title.toUpperCase()}`, margin, y, contentWidth);
    y += 8;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8.5);
    doc.setTextColor(80, 90, 110);
    doc.text('Información relevante:', margin, y);
    y += 4;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(55, 65, 85);
    block.relevant.forEach(paragraph => {
      const lines = doc.splitTextToSize(paragraph, contentWidth);
      y = ensurePdfSpace(doc, y, lines.length * 4 + 2);
      doc.text(lines, margin, y);
      y += lines.length * 4 + 1;
    });

    y += 2;
    y = ensurePdfSpace(doc, y, 14);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(8.5);
    doc.setTextColor(80, 90, 110);
    doc.text('Información extra:', margin, y);
    y += 4;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    doc.setTextColor(55, 65, 85);
    block.extra.forEach(item => {
      const lines = doc.splitTextToSize(`- ${item}`, contentWidth);
      y = ensurePdfSpace(doc, y, lines.length * 4 + 1);
      doc.text(lines, margin, y);
      y += lines.length * 4 + 1;
    });

    if (idx < keys.length - 1) y += 5;
  });

  return y;
}

